SELECT company_name, ceo_name
FROM companies
WHERE sector = 'Technology' AND ceo_name LIKE 'A%';

SELECT company_name, market_cap
FROM companies
WHERE sector = 'Tech';

SELECT company_name, total_nsg
FROM (
    SELECT company_name, total_nsg, ROW_NUMBER() OVER (ORDER BY total_nsg DESC) AS rank
    FROM companies
) AS ranked_companies
WHERE rank <= 3;
